using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

// Load and prepare data
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age), nameof(CustomerData.Income), "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(CustomerData.Churned)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression())
    .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

// Train/test split and evaluate
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
var model = pipeline.Fit(split.TrainSet);
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");

// Retrain on full dataset and save
var fullModel = pipeline.Fit(dataView);
mlContext.Model.Save(fullModel, dataView.Schema, modelPath);

// Register pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "ChurnPredictor API — POST /predict with {age, income, region, purchaseHistory}");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

namespace ChurnPredictor.Models
{
    public sealed class CustomerData
    {
        [LoadColumn(0)] public float Age { get; set; }
        [LoadColumn(1)] public float Income { get; set; }
        [LoadColumn(2)] public string Region { get; set; } = string.Empty;
        [LoadColumn(3)] public float PurchaseHistory { get; set; }
        [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
    }

    public sealed class ChurnPrediction
    {
        [ColumnName("PredictedLabel")]
        public string PredictedLabel { get; set; } = string.Empty;
        public float Probability { get; set; }
        public float Score { get; set; }
    }

    public sealed record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);
}

